library(haven); library(dplyr); library(readr); w1 <- read_delim("data/input/wave_one_lsype_family_background_2020.tab", delim="\t", show_col_types=FALSE); w2 <- read_delim("data/input/wave_two_lsype_family_background_2020.tab", delim="\t", show_col_types=FALSE); w4 <- read_delim("data/input/wave_four_lsype_family_background_2020.tab", delim="\t", show_col_types=FALSE); w1s <- w1[,c("NSID","W1hiqualmum","W1hiqualdad")]; w2s <- w2[,c("NSID","W2hiqualmum","W2hiqualdad")]; w4s <- w4[,c("NSID","w4hiqualmum","w4hiqualdad")]; m <- merge(merge(w1s,w2s,by="NSID",all=TRUE),w4s,by="NSID",all=TRUE); hm <- function(x) ifelse(x==-999,-2,ifelse(x==-99,-3,ifelse(x==-98,-3,ifelse(x==-94,-8,ifelse(x==-92,-9,ifelse(x==-91,-1,x)))))); hd <- function(x) ifelse(x==-999,-2,ifelse(x==-99,-3,ifelse(x==-98,-3,ifelse(x==-94,-8,ifelse(x==-92,-9,ifelse(x==-91,-1,ifelse(x==-1,-8,x))))))); h4 <- function(x) ifelse(x==-999,-2,ifelse(x==-99,-3,ifelse(x==-98,-3,ifelse(x==-94,-8,ifelse(x==-92,-9,ifelse(x==-91,-1,x)))))); m$m1h <- hm(m$W1hiqualmum); m$d1h <- hd(m$W1hiqualdad); m$m2h <- hm(m$W2hiqualmum); m$d2h <- hd(m$W2hiqualdad); m$m4h <- h4(m$w4hiqualmum); m$d4h <- h4(m$w4hiqualdad); cons <- function(a,b,c) sapply(1:length(a), function(i) { v <- c(a[i],b[i],c[i]); v <- v[!is.na(v)]; if(length(v)==0) return(-3); p <- v[v>=1 & v<=20]; if(length(p)>0) return(p[1]); return(v[1]) }); m$educdtlma <- cons(m$m1h,m$m2h,m$m4h); m$educdtlpa <- cons(m$d1h,m$d2h,m$d4h); col <- function(x) ifelse(x<0,x,ifelse(x<=4,0,ifelse(x<=17,1,ifelse(x==18,2,ifelse(x==19,3,ifelse(x==20,4,NA)))))); m$educma <- col(m$educdtlma); m$educpa <- col(m$educdtlpa); f <- m[,c("NSID","educma","educpa","educdtlma","educdtlpa")]; dir.create("data/output",showWarnings=FALSE,recursive=TRUE); write.csv(f,"data/output/cleaned_data.csv",row.names=FALSE); cat("Done:",nrow(f),"rows\n")